const { ApolloServer, gql } = require('apollo-server');

// Define the schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    comments: [Comment]
    author: User
  }

  type Comment {
    id: ID!
    text: String!
    post: Post
    user: User
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
  }
`;

// Define the resolvers
const resolvers = {
  User: {
    posts: (parent, args, context) => {
      // Fetch posts for a user from the database
      return context.prisma.user.findUnique({ where: { id: parent.id } }).posts();
    },
  },
  Post: {
    comments: (parent, args, context) => {
      // Fetch comments for a post from the database
      return context.prisma.post.findUnique({ where: { id: parent.id } }).comments();
    },
    author: (parent, args, context) => {
      // Fetch the author of a post from the database
      return context.prisma.post.findUnique({ where: { id: parent.id } }).author();
    },
  },
  Comment: {
    post: (parent, args, context) => {
      // Fetch the post for a comment from the database
      return context.prisma.comment.findUnique({ where: { id: parent.id } }).post();
    },
    user: (parent, args, context) => {
      // Fetch the user who made a comment from the database
      return context.prisma.comment.findUnique({ where: { id: parent.id } }).user();
    },
  },
  Query: {
    users: (parent, args, context) => {
      // Fetch all users from the database
      return context.prisma.user.findMany();
    },
    posts: (parent, args, context) => {
      // Fetch all posts from the database
      return context.prisma.post.findMany();
    },
    comments: (parent, args, context) => {
      // Fetch all comments from the database
      return context.prisma.comment.findMany();
    },
  },
};

// Create the Apollo Server
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});